=<!DOCTYPE html>
<html lang="pt-BR">
<head>
    <meta charset="UTF-8">
    <meta name="viewport" content="width=device-width, initial-scale=1.0">
    <title>Farmácia - Atendimento Virtual</title>
    <link rel="preconnect" href="https://fonts.googleapis.com">
    <link rel="preconnect" href="https://fonts.gstatic.com" crossorigin>
    <link href="https://fonts.googleapis.com/css2?family=Inter:wght@400;500;600;700&display=swap" rel="stylesheet">
    <style>
        * {
            margin: 0;
            padding: 0;
            box-sizing: border-box;
        }

        :root {
            --primary: #0d9488;
            --primary-dark: #0f766e;
            --primary-light: #14b8a6;
            --bg-dark: #111827;
            --bg-card: #1f2937;
            --bg-input: #374151;
            --text-primary: #f9fafb;
            --text-secondary: #9ca3af;
            --text-muted: #6b7280;
            --border: #374151;
            --success: #10b981;
            --error: #ef4444;
            --message-user: #0d9488;
            --message-bot: #374151;
        }

        html, body {
            height: 100%;
            overflow: hidden;
        }

        body {
            font-family: 'Inter', -apple-system, BlinkMacSystemFont, sans-serif;
            background: var(--bg-dark);
            color: var(--text-primary);
            display: flex;
            flex-direction: column;
        }

        .header {
            background: var(--bg-card);
            border-bottom: 1px solid var(--border);
            padding: 1rem 1.5rem;
            display: flex;
            align-items: center;
            gap: 1rem;
            position: sticky;
            top: 0;
            z-index: 100;
        }

        .header-avatar {
            width: 48px;
            height: 48px;
            background: linear-gradient(135deg, var(--primary), var(--primary-light));
            border-radius: 50%;
            display: flex;
            align-items: center;
            justify-content: center;
            font-size: 1.5rem;
        }

        .header-info h1 {
            font-size: 1.125rem;
            font-weight: 600;
        }

        .header-info p {
            font-size: 0.875rem;
            color: var(--success);
            display: flex;
            align-items: center;
            gap: 0.375rem;
        }

        .header-info p::before {
            content: '';
            width: 8px;
            height: 8px;
            background: var(--success);
            border-radius: 50%;
        }

        .header-actions {
            margin-left: auto;
        }

        .header-btn {
            background: var(--bg-input);
            border: none;
            color: var(--text-secondary);
            width: 40px;
            height: 40px;
            border-radius: 50%;
            cursor: pointer;
            display: flex;
            align-items: center;
            justify-content: center;
            transition: all 0.2s;
        }

        .header-btn:hover {
            background: var(--primary);
            color: white;
        }

        .chat-container {
            flex: 1;
            overflow-y: auto;
            overflow-x: hidden;
            padding: 1.5rem;
            display: flex;
            flex-direction: column;
            gap: 1rem;
            max-width: 900px;
            margin: 0 auto;
            width: 100%;
            scroll-behavior: smooth;
        }

        .message {
            display: flex;
            gap: 0.75rem;
            max-width: 85%;
            animation: slideIn 0.3s ease;
        }

        @keyframes slideIn {
            from { opacity: 0; transform: translateY(10px); }
            to { opacity: 1; transform: translateY(0); }
        }

        .message.user {
            margin-left: auto;
            flex-direction: row-reverse;
        }

        .message-avatar {
            width: 36px;
            height: 36px;
            border-radius: 50%;
            display: flex;
            align-items: center;
            justify-content: center;
            font-size: 0.875rem;
            flex-shrink: 0;
        }

        .message.bot .message-avatar {
            background: linear-gradient(135deg, var(--primary), var(--primary-light));
        }

        .message.user .message-avatar {
            background: var(--bg-input);
        }

        .message-content {
            background: var(--message-bot);
            padding: 0.875rem 1rem;
            border-radius: 1rem;
        }

        .message.user .message-content {
            background: var(--message-user);
        }

        .message.bot .message-content {
            border-top-left-radius: 0.25rem;
        }

        .message.user .message-content {
            border-top-right-radius: 0.25rem;
        }

        .message-text {
            font-size: 0.9375rem;
            line-height: 1.5;
            word-wrap: break-word;
            white-space: pre-wrap;
        }

        .message-time {
            font-size: 0.75rem;
            color: var(--text-muted);
            margin-top: 0.375rem;
        }

        .message.user .message-time {
            text-align: right;
        }

        .message-attachment {
            margin-top: 0.5rem;
            border-radius: 0.5rem;
            overflow: hidden;
        }

        .message-attachment img {
            max-width: 100%;
            max-height: 300px;
            border-radius: 0.5rem;
        }

        .message-attachment audio {
            width: 100%;
            max-width: 300px;
        }

        .message-document {
            display: flex;
            align-items: center;
            gap: 0.75rem;
            background: rgba(0, 0, 0, 0.2);
            padding: 0.75rem;
            border-radius: 0.5rem;
        }

        .message-document-icon {
            width: 40px;
            height: 40px;
            background: var(--primary);
            border-radius: 0.5rem;
            display: flex;
            align-items: center;
            justify-content: center;
        }

        .message-document-name {
            font-size: 0.875rem;
            font-weight: 500;
        }

        .message-document-size {
            font-size: 0.75rem;
            color: var(--text-muted);
        }

        .typing-indicator {
            display: none;
            gap: 0.75rem;
            max-width: 85%;
        }

        .typing-indicator.active {
            display: flex;
        }

        .typing-dots {
            display: flex;
            gap: 4px;
            padding: 1rem;
            background: var(--message-bot);
            border-radius: 1rem;
            border-top-left-radius: 0.25rem;
        }

        .typing-dots span {
            width: 8px;
            height: 8px;
            background: var(--text-muted);
            border-radius: 50%;
            animation: typing 1.4s infinite;
        }

        .typing-dots span:nth-child(2) { animation-delay: 0.2s; }
        .typing-dots span:nth-child(3) { animation-delay: 0.4s; }

        @keyframes typing {
            0%, 60%, 100% { transform: translateY(0); opacity: 0.4; }
            30% { transform: translateY(-4px); opacity: 1; }
        }

        .input-area {
            background: var(--bg-card);
            border-top: 1px solid var(--border);
            padding: 1rem 1.5rem;
            position: sticky;
            bottom: 0;
        }

        .preview-area {
            display: none;
            padding: 0.75rem 1rem;
            background: var(--bg-input);
            border-radius: 0.75rem;
            margin-bottom: 0.75rem;
            max-width: 900px;
            margin-left: auto;
            margin-right: auto;
            align-items: center;
            gap: 0.75rem;
        }

        .preview-area.active {
            display: flex;
        }

        .preview-content {
            flex: 1;
            display: flex;
            align-items: center;
            gap: 0.75rem;
            min-width: 0;
        }

        .preview-content img {
            width: 60px;
            height: 60px;
            object-fit: cover;
            border-radius: 0.5rem;
        }

        .preview-info {
            flex: 1;
            min-width: 0;
        }

        .preview-name {
            font-size: 0.875rem;
            font-weight: 500;
            white-space: nowrap;
            overflow: hidden;
            text-overflow: ellipsis;
        }

        .preview-size {
            font-size: 0.75rem;
            color: var(--text-muted);
        }

        .preview-close {
            background: none;
            border: none;
            color: var(--text-secondary);
            width: 32px;
            height: 32px;
            border-radius: 50%;
            cursor: pointer;
            display: flex;
            align-items: center;
            justify-content: center;
        }

        .preview-close:hover {
            background: rgba(255, 255, 255, 0.1);
            color: var(--error);
        }

        .input-container {
            max-width: 900px;
            margin: 0 auto;
            display: flex;
            gap: 0.75rem;
            align-items: flex-end;
        }

        .input-actions {
            display: flex;
            gap: 0.25rem;
        }

        .input-btn {
            background: none;
            border: none;
            color: var(--text-secondary);
            width: 44px;
            height: 44px;
            border-radius: 50%;
            cursor: pointer;
            display: flex;
            align-items: center;
            justify-content: center;
            transition: all 0.2s;
            position: relative;
        }

        .input-btn:hover {
            background: var(--bg-input);
            color: var(--primary-light);
        }

        .input-btn input[type="file"] {
            position: absolute;
            opacity: 0;
            width: 100%;
            height: 100%;
            cursor: pointer;
        }

        .input-wrapper {
            flex: 1;
            display: flex;
            align-items: flex-end;
            background: var(--bg-input);
            border-radius: 1.5rem;
            padding: 0.5rem 1rem;
        }

        .input-wrapper textarea {
            flex: 1;
            background: none;
            border: none;
            color: var(--text-primary);
            font-size: 0.9375rem;
            font-family: inherit;
            resize: none;
            max-height: 150px;
            line-height: 1.5;
            padding: 0.375rem 0;
        }

        .input-wrapper textarea::placeholder {
            color: var(--text-muted);
        }

        .input-wrapper textarea:focus {
            outline: none;
        }

        .send-btn {
            background: var(--primary);
            border: none;
            color: white;
            width: 44px;
            height: 44px;
            border-radius: 50%;
            cursor: pointer;
            display: flex;
            align-items: center;
            justify-content: center;
            transition: all 0.2s;
            flex-shrink: 0;
        }

        .send-btn:hover {
            background: var(--primary-dark);
            transform: scale(1.05);
        }

        .send-btn:disabled {
            background: var(--bg-input);
            color: var(--text-muted);
            cursor: not-allowed;
            transform: none;
        }

        .welcome-message {
            text-align: center;
            padding: 3rem 1rem;
        }

        .welcome-icon {
            width: 80px;
            height: 80px;
            background: linear-gradient(135deg, var(--primary), var(--primary-light));
            border-radius: 50%;
            display: flex;
            align-items: center;
            justify-content: center;
            margin: 0 auto 1.5rem;
            font-size: 2.5rem;
        }

        .welcome-message h2 {
            font-size: 1.5rem;
            font-weight: 600;
            margin-bottom: 0.5rem;
        }

        .welcome-message p {
            color: var(--text-secondary);
            max-width: 400px;
            margin: 0 auto;
        }

        .toast {
            position: fixed;
            bottom: 100px;
            left: 50%;
            transform: translateX(-50%) translateY(100px);
            background: var(--bg-card);
            border: 1px solid var(--border);
            padding: 0.875rem 1.25rem;
            border-radius: 0.75rem;
            opacity: 0;
            transition: all 0.3s;
            z-index: 1001;
        }

        .toast.active {
            transform: translateX(-50%) translateY(0);
            opacity: 1;
        }

        .toast.error {
            border-color: var(--error);
        }

        @media (max-width: 640px) {
            .header { padding: 0.875rem 1rem; }
            .chat-container { padding: 1rem; }
            .input-area { padding: 0.875rem 1rem; }
            .message { max-width: 90%; }
        }

        ::-webkit-scrollbar { width: 6px; }
        ::-webkit-scrollbar-track { background: transparent; }
        ::-webkit-scrollbar-thumb { background: var(--border); border-radius: 3px; }
    </style>
</head>
<body>
    <header class="header">
        <div class="header-avatar">💊</div>
        <div class="header-info">
            <h1>Farmácia - Atendimento</h1>
            <p>Online</p>
        </div>
        <div class="header-actions">
            <button class="header-btn" id="clearBtn" title="Limpar conversa">
                <svg width="20" height="20" viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="2">
                    <path d="M3 6h18M8 6V4a2 2 0 012-2h4a2 2 0 012 2v2m3 0v14a2 2 0 01-2 2H7a2 2 0 01-2-2V6h14z"/>
                </svg>
            </button>
        </div>
    </header>

    <div class="chat-container" id="chatContainer">
        <div class="welcome-message">
            <div class="welcome-icon">💊</div>
            <h2>Olá! Sou a Sofia 👋</h2>
            <p>Assistente virtual da Farmácia. Posso ajudar com preços, disponibilidade de medicamentos e delivery!</p>
        </div>
    </div>

    <div class="typing-indicator" id="typingIndicator">
        <div class="message-avatar">💊</div>
        <div class="typing-dots">
            <span></span>
            <span></span>
            <span></span>
        </div>
    </div>

    <div class="input-area">
        <div class="preview-area" id="previewArea">
            <div class="preview-content" id="previewContent"></div>
            <button class="preview-close" id="previewClose">
                <svg width="18" height="18" viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="2">
                    <path d="M18 6L6 18M6 6l12 12"/>
                </svg>
            </button>
        </div>

        <div class="input-container">
            <div class="input-actions">
                <button class="input-btn" id="imageBtn" title="Enviar imagem">
                    <input type="file" accept="image/*" id="imageInput">
                    <svg width="22" height="22" viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="2">
                        <rect x="3" y="3" width="18" height="18" rx="2" ry="2"/>
                        <circle cx="8.5" cy="8.5" r="1.5"/>
                        <path d="M21 15l-5-5L5 21"/>
                    </svg>
                </button>

                <button class="input-btn" id="docBtn" title="Enviar documento">
                    <input type="file" accept=".pdf,.doc,.docx,.txt,.xls,.xlsx" id="docInput">
                    <svg width="22" height="22" viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="2">
                        <path d="M14 2H6a2 2 0 00-2 2v16a2 2 0 002 2h12a2 2 0 002-2V8z"/>
                        <polyline points="14,2 14,8 20,8"/>
                        <line x1="16" y1="13" x2="8" y2="13"/>
                        <line x1="16" y1="17" x2="8" y2="17"/>
                    </svg>
                </button>

            </div>

            <div class="input-wrapper">
                <textarea id="messageInput" placeholder="Digite sua mensagem..." rows="1"></textarea>
            </div>

            <button class="send-btn" id="sendBtn" disabled>
                <svg width="20" height="20" viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="2">
                    <line x1="22" y1="2" x2="11" y2="13"/>
                    <polygon points="22,2 15,22 11,13 2,9"/>
                </svg>
            </button>
        </div>
    </div>

    <div class="toast" id="toast">
        <span id="toastMessage"></span>
    </div>

    <script>
        (function() {
            // Constants
            var WEBHOOK_URL = 'https://webhook.fluxon.app.br/webhook/farmacia';
            var INSTANCE_NAME = 'minha-empresa-d4bdb5';
            var USER_PHONE = '5500000000000';
            var USER_NAME = 'Cliente Web';

            // State
            var pendingFile = null;
            var pendingFileType = null;
            var conversationId = null;

            // Elements
            var chatContainer;
            var messageInput;
            var sendBtn;
            var typingIndicator;
            var previewArea;
            var previewContent;
            var previewClose;
            var clearBtn;
            var imageInput;
            var docInput;
            var toast;
            var toastMessage;

            // Wait for DOM
            document.addEventListener('DOMContentLoaded', init);

            function generateConversationId() {
                return 'CONV' + Date.now().toString(36).toUpperCase() + Math.random().toString(36).substring(2, 10).toUpperCase();
            }

            function init() {
                // Generate conversation ID for this session
                conversationId = generateConversationId();
                console.log('Conversation ID:', conversationId);

                // Get elements
                chatContainer = document.getElementById('chatContainer');
                messageInput = document.getElementById('messageInput');
                sendBtn = document.getElementById('sendBtn');
                typingIndicator = document.getElementById('typingIndicator');
                previewArea = document.getElementById('previewArea');
                previewContent = document.getElementById('previewContent');
                previewClose = document.getElementById('previewClose');
                clearBtn = document.getElementById('clearBtn');
                imageInput = document.getElementById('imageInput');
                docInput = document.getElementById('docInput');
                toast = document.getElementById('toast');
                toastMessage = document.getElementById('toastMessage');

                // Event Listeners
                messageInput.addEventListener('input', function() {
                    autoResize(messageInput);
                    updateSendButton();
                });

                messageInput.addEventListener('keydown', function(e) {
                    if (e.key === 'Enter' && !e.shiftKey) {
                        e.preventDefault();
                        if (!sendBtn.disabled) {
                            sendMessage();
                        }
                    }
                });

                sendBtn.addEventListener('click', sendMessage);
                clearBtn.addEventListener('click', clearChat);
                previewClose.addEventListener('click', clearPreview);
                imageInput.addEventListener('change', handleImageUpload);
                docInput.addEventListener('change', handleDocumentUpload);
            }

            function updateSendButton() {
                sendBtn.disabled = !messageInput.value.trim() && !pendingFile;
            }

            function autoResize(el) {
                el.style.height = 'auto';
                el.style.height = Math.min(el.scrollHeight, 150) + 'px';
            }

            function formatTime(date) {
                return date.toLocaleTimeString('pt-BR', { hour: '2-digit', minute: '2-digit' });
            }

            function formatFileSize(bytes) {
                if (bytes < 1024) return bytes + ' B';
                if (bytes < 1024 * 1024) return (bytes / 1024).toFixed(1) + ' KB';
                return (bytes / (1024 * 1024)).toFixed(1) + ' MB';
            }

            function generateMessageId() {
                return 'WEB' + Date.now().toString(36).toUpperCase() + Math.random().toString(36).substring(2, 8).toUpperCase();
            }

            function showToast(message, type) {
                toast.className = 'toast ' + (type || '');
                toastMessage.textContent = message;
                toast.classList.add('active');
                setTimeout(function() {
                    toast.classList.remove('active');
                }, 3000);
            }

            function scrollToBottom() {
                requestAnimationFrame(function() {
                    chatContainer.scrollTop = chatContainer.scrollHeight;
                    // Fallback para garantir
                    setTimeout(function() {
                        chatContainer.scrollTop = chatContainer.scrollHeight;
                    }, 50);
                });
            }

            function showTyping() {
                typingIndicator.classList.add('active');
                chatContainer.appendChild(typingIndicator);
                typingIndicator.scrollIntoView({ behavior: 'smooth', block: 'end' });
            }

            function hideTyping() {
                typingIndicator.classList.remove('active');
            }

            function addMessage(content, isUser, attachment) {
                var welcome = chatContainer.querySelector('.welcome-message');
                if (welcome) welcome.remove();

                var message = document.createElement('div');
                message.className = 'message ' + (isUser ? 'user' : 'bot');

                var attachmentHtml = '';
                if (attachment) {
                    if (attachment.type === 'image') {
                        attachmentHtml = '<div class="message-attachment"><img src="' + attachment.data + '" alt="Imagem"></div>';
                    } else if (attachment.type === 'audio') {
                        attachmentHtml = '<div class="message-attachment"><audio controls src="' + attachment.data + '"></audio></div>';
                    } else if (attachment.type === 'document') {
                        attachmentHtml = '<div class="message-attachment"><div class="message-document"><div class="message-document-icon"><svg width="20" height="20" viewBox="0 0 24 24" fill="none" stroke="white" stroke-width="2"><path d="M14 2H6a2 2 0 00-2 2v16a2 2 0 002 2h12a2 2 0 002-2V8z"/><polyline points="14,2 14,8 20,8"/></svg></div><div><div class="message-document-name">' + attachment.name + '</div><div class="message-document-size">' + attachment.size + '</div></div></div></div>';
                    }
                }

                message.innerHTML = '<div class="message-avatar">' + (isUser ? '👤' : '💊') + '</div><div class="message-content">' + (content ? '<div class="message-text">' + content + '</div>' : '') + attachmentHtml + '<div class="message-time">' + formatTime(new Date()) + '</div></div>';

                chatContainer.appendChild(message);
                message.scrollIntoView({ behavior: 'smooth', block: 'end' });
            }

            function showPreview(iconHtml, name, size) {
                previewContent.innerHTML = iconHtml + '<div class="preview-info"><div class="preview-name">' + name + '</div><div class="preview-size">' + size + '</div></div>';
                previewArea.classList.add('active');
            }

            function clearPreview() {
                previewArea.classList.remove('active');
                previewContent.innerHTML = '';
                pendingFile = null;
                pendingFileType = null;
                updateSendButton();
            }

            function clearChat() {
                chatContainer.innerHTML = '<div class="welcome-message"><div class="welcome-icon">💊</div><h2>Olá! Sou a Sofia 👋</h2><p>Assistente virtual da Farmácia. Posso ajudar com preços, disponibilidade de medicamentos e delivery!</p></div>';
                // Generate new conversation ID when clearing chat
                conversationId = generateConversationId();
                console.log('New Conversation ID:', conversationId);
                showToast('Conversa limpa!', 'success');
            }

            function handleImageUpload(e) {
                var file = e.target.files[0];
                if (!file) return;

                if (file.size > 10 * 1024 * 1024) {
                    showToast('Imagem muito grande. Máximo 10MB.', 'error');
                    return;
                }

                var reader = new FileReader();
                reader.onload = function(ev) {
                    pendingFile = {
                        data: ev.target.result,
                        name: file.name,
                        size: formatFileSize(file.size),
                        mimetype: file.type
                    };
                    pendingFileType = 'image';
                    showPreview('<img src="' + ev.target.result + '" alt="Preview">', file.name, formatFileSize(file.size));
                    updateSendButton();
                };
                reader.readAsDataURL(file);
                e.target.value = '';
            }

            function handleDocumentUpload(e) {
                var file = e.target.files[0];
                if (!file) return;

                if (file.size > 25 * 1024 * 1024) {
                    showToast('Documento muito grande. Máximo 25MB.', 'error');
                    return;
                }

                var reader = new FileReader();
                reader.onload = function(ev) {
                    pendingFile = {
                        data: ev.target.result,
                        name: file.name,
                        size: formatFileSize(file.size),
                        mimetype: file.type
                    };
                    pendingFileType = 'document';
                    var icon = '<div style="width:60px;height:60px;background:var(--primary);border-radius:0.5rem;display:flex;align-items:center;justify-content:center"><svg width="28" height="28" viewBox="0 0 24 24" fill="none" stroke="white" stroke-width="2"><path d="M14 2H6a2 2 0 00-2 2v16a2 2 0 002 2h12a2 2 0 002-2V8z"/><polyline points="14,2 14,8 20,8"/></svg></div>';
                    showPreview(icon, file.name, formatFileSize(file.size));
                    updateSendButton();
                };
                reader.readAsDataURL(file);
                e.target.value = '';
            }

            function sendMessage() {
                var text = messageInput.value.trim();
                if (!text && !pendingFile) return;

                var attachment = null;
                if (pendingFile) {
                    attachment = {
                        type: pendingFileType,
                        data: pendingFile.data,
                        name: pendingFile.name,
                        size: pendingFile.size
                    };
                }

                addMessage(text, true, attachment);

                messageInput.value = '';
                sendBtn.disabled = true;
                autoResize(messageInput);

                var timestamp = Math.floor(Date.now() / 1000);
                var messageId = generateMessageId();
                var remoteJid = USER_PHONE + '@s.whatsapp.net';

                var messageContent = {};
                var messageType = 'conversation';

                if (pendingFileType === 'audio' && pendingFile) {
                    messageType = 'audioMessage';
                    messageContent = {
                        audioMessage: {
                            url: pendingFile.data,
                            mimetype: pendingFile.mimetype || 'audio/ogg'
                        }
                    };
                } else if (pendingFileType === 'image' && pendingFile) {
                    messageType = 'imageMessage';
                    messageContent = {
                        imageMessage: {
                            url: pendingFile.data,
                            caption: text || '',
                            mimetype: pendingFile.mimetype || 'image/jpeg'
                        }
                    };
                } else if (pendingFileType === 'document' && pendingFile) {
                    messageType = 'documentMessage';
                    messageContent = {
                        documentMessage: {
                            url: pendingFile.data,
                            fileName: pendingFile.name,
                            mimetype: pendingFile.mimetype || 'application/pdf'
                        }
                    };
                } else {
                    messageContent = {
                        conversation: text
                    };
                }

                var payload = {
                    event: 'messages.upsert',
                    instance: INSTANCE_NAME,
                    data: {
                        key: {
                            remoteJid: remoteJid,
                            fromMe: false,
                            id: messageId
                        },
                        pushName: USER_NAME,
                        status: 'DELIVERY_ACK',
                        message: messageContent,
                        messageType: messageType,
                        messageTimestamp: timestamp,
                        source: 'web',
                        conversationId: conversationId
                    },
                    sender: remoteJid,
                    server_url: window.location.origin,
                    apikey: 'web-client',
                    conversationId: conversationId
                };

                clearPreview();
                showTyping();

                fetch(WEBHOOK_URL, {
                    method: 'POST',
                    headers: {
                        'Content-Type': 'application/json'
                    },
                    body: JSON.stringify(payload)
                })
                .then(function(response) {
                    if (!response.ok) throw new Error('HTTP ' + response.status);
                    return response.json();
                })
                .then(function(data) {
                    hideTyping();
                    var botResponse = '';

                    if (typeof data === 'string') {
                        botResponse = data;
                    } else if (data.output) {
                        botResponse = data.output;
                    } else if (data.message) {
                        botResponse = data.message;
                    } else if (data.text) {
                        botResponse = data.text;
                    } else if (data.response) {
                        botResponse = data.response;
                    } else if (Array.isArray(data) && data[0]) {
                        botResponse = data[0].output || data[0].message || data[0].text || JSON.stringify(data[0]);
                    }

                    if (botResponse) {
                        addMessage(botResponse, false);
                    }
                })
                .catch(function(error) {
                    hideTyping();
                    console.error('Error:', error);
                    showToast('Erro ao enviar mensagem.', 'error');
                });
            }
        })();
    </script>
</body>
